definition.script:
pipeline {
    agent any
    tools {
        maven 'maven9'
        jdk 'jdk17'
    }
    parameters {
        // FIXED: Changed 'defaultvalue' to 'defaultValue'
        string(name: 'BRANCH_NAME', defaultValue: 'main', description: 'Git branch to build')
    }
    stages {
        stage('Git Checkout') {
            steps {
                // FIXED: Changed single quotes to double quotes and fixed parameter syntax
                git branch: "${params.BRANCH_NAME}", url: 'https://github.com/jaiswaladi246/Boardgame.git'
            }
        }

        stage('Compile') {
            steps {
               sh "mvn compile"
            }
        }

        stage('Test') {
            steps {
                 sh "mvn test"
            }
        }

        stage('Build') {
            steps {
                 sh "mvn package"
            }
        }
    }
  post {
      success {
          echo "correct pipeline is success"
      }
      failure {
          echo "failure pipleline is failed"
      }
      always {
          echo "Job complated at: ${new Date()}"
      }
  }

}
